import * as t from "io-ts";

import { BaseBridgeFundsIntent } from "./baseBridgeFundsIntent";
import { Optional } from "../../../utils";
import { FeeOption } from "./feeOption";
import { EIP1559FeeOptions } from "./eip1559FeeOptions";

/**
 * @title Hypeevm Bridge Funds Intent
 * Intent for bridging assets from HyperCore to HyperEVM
 *
 * The amount.symbol field identifies the asset to bridge (e.g., "HYPE", "USDC")
 * The amount.value specifies how much to bridge
 */
export const HypeevmBridgeFundsIntent = t.intersection([
  BaseBridgeFundsIntent,
  t.partial({
    feeOptions: Optional(t.union([FeeOption, EIP1559FeeOptions])),
  }),
]);

export type HypeevmBridgeFundsIntent = t.TypeOf<
  typeof HypeevmBridgeFundsIntent
>;
